import re
import json

with open\('js/data.js', 'r', encoding='utf-8'\) as f:
    content = f.read\(\)

# Extract the RESTAURANTS array
match = re.search\(r'const RESTAURANTS = \(\\[[\\s\\S]*?\\n\\];\)', content\)
if match:
    json_str = match.group\(1\)[:-1]  # Remove trailing semicolon
    restaurants = json.loads\(json_str\)

    print\(f"Total restaurants: {len\(restaurants\)}"\)

    # Count cooking methods
    cooking_count = {}
    occasion_count = {}
    restaurants_by_cooking = {}
    restaurants_by_occasion = {}

    for r in restaurants:
        if 'tags' in r:
            # Cooking
            for c in r.get\('cooking', []\):
                cooking_count[c] = cooking_count.get\(c, 0\) + 1
                if c not in restaurants_by_cooking:
                    restaurants_by_cooking[c] = []
                restaurants_by_cooking[c].append\(r['id']\)

            # Occasion
            for o in r.get\('occasion', []\):
                occasion_count[o] = occasion_count.get\(o, 0\) + 1
                if o not in restaurants_by_occasion:
                    restaurants_by_occasion[o] = []
                restaurants_by_occasion[o].append\(r['id']\)

    print\("\\n=== 조리 방식 \(COOKING\) ==="\)
    for method in sorted\(cooking_count.keys\(\), key=lambda x: cooking_count[x], reverse=True\):
        print\(f"  {method}: {cooking_count[method]} restaurants"\)

    print\("\\n=== 상황·목적 \(OCCASION\) ==="\)
    for occasion in sorted\(occasion_count.keys\(\), key=lambda x: occasion_count[x], reverse=True\):
        print\(f"  {occasion}: {occasion_count[occasion]} restaurants"\)

    # Check for multiple tags
    print\("\\n=== Restaurants with Multiple Values ==="\)
    multi_cooking = 0
    multi_occasion = 0
    for r in restaurants:
        if 'tags' in r:
            if len\(r.get\('cooking', []\)\) > 1:
                multi_cooking += 1
            if len\(r.get\('occasion', []\)\) > 1:
                multi_occasion += 1

    print\(f"  Restaurants with multiple cooking methods: {multi_cooking}"\)
    print\(f"  Restaurants with multiple occasions: {multi_occasion}"\)

